1	import { useEffect, useMemo, useState } from "react";
2	import ReactMarkdown from "react-markdown";
3	import remarkGfm from "remark-gfm";
4	import {
5	  fetchIncremental,
6	  runSimIngest,
7	  type SimDay,
8	  type SimIngestResponse,
9	  type SimItem,
10	} from "../api";
11	import { cn } from "../lib/cn";
12	
13	type Kind = "email" | "invoice" | "bank";
14	type Mode = "isolated" | "live";
15	
16	const KIND_LABELS: Record<Kind, string> = {
17	  email: "Emails",
18	  invoice: "Invoices",
19	  bank: "Bank tx",
20	};
21	
22	export function IngestPage() {
23	  const [days, setDays] = useState<SimDay[] | null>(null);
24	  const [error, setError] = useState<string | null>(null);
25	  const [day, setDay] = useState<number | null>(null);
26	  const [kind, setKind] = useState<Kind>("email");
27	  const [itemId, setItemId] = useState<string | null>(null);
28	  const [mode, setMode] = useState<Mode>("isolated");
29	  const [running, setRunning] = useState(false);
30	  const [result, setResult] = useState<SimIngestResponse | null>(null);
31	  const [activeFile, setActiveFile] = useState<string | null>(null);
32	
33	  useEffect(() => {
34	    fetchIncremental()
35	      .then((d) => {
36	        setDays(d);
37	        if (d.length > 0) setDay(d[d.length - 1].day);
38	      })
39	      .catch((e) => setError(String(e)));
40	  }, []);
41	
42	  const currentDay = useMemo(
43	    () => days?.find((d) => d.day === day) ?? null,
44	    [days, day],
45	  );
46	
47	  const items: SimItem[] = useMemo(() => {
48	    if (!currentDay) return [];
49	    if (kind === "email") return currentDay.emails;
50	    if (kind === "invoice") return currentDay.invoices;
51	    return currentDay.bank;
52	  }, [currentDay, kind]);
53	
54	  useEffect(() => {
55	    if (items.length === 0) {
56	      setItemId(null);
57	      return;
58	    }
59	    if (!itemId || !items.some((i) => i.id === itemId)) {
60	      setItemId(items[0].id);
61	    }
62	  }, [items, itemId]);
63	
64	  useEffect(() => {
65	    if (!result) {
66	      setActiveFile(null);
67	      return;
68	    }
69	    setActiveFile(result.files[0]?.path ?? null);
70	  }, [result]);
71	
72	  async function handleRun() {
73	    if (!day || !itemId) return;
74	    setRunning(true);
75	    setError(null);
76	    setResult(null);
77	    try {
78	      const res = await runSimIngest({ day, kind, id: itemId, mode });
79	      setResult(res);
80	    } catch (e) {
81	      setError(String(e));
82	    } finally {
83	      setRunning(false);
84	    }
85	  }
86	
87	  const activeContent =
88	    result?.files.find((f) => f.path === activeFile)?.content ?? "";
89	
90	  return (
91	    <div className="flex h-screen flex-col bg-[var(--color-bg)] text-[var(--color-fg)]">
92	      <header className="glass flex h-12 shrink-0 items-center gap-3 border-b border-[var(--color-border)] px-4">
93	        <a
94	          href="/"
95	          className="font-display text-[19.5px] font-medium text-[var(--color-ink-50)] hover:text-[var(--color-accent)]"
96	        >
97	          ← Buena Wiki
98	        </a>
99	        <span className="text-[16.5px] uppercase tracking-[0.18em] text-[var(--color-fg-muted)]">
100	          Simulate ingest
101	        </span>
102	      </header>
103	
104	      <div className="flex min-h-0 flex-1">
105	        <aside className="flex w-[360px] shrink-0 flex-col border-r border-[var(--color-border)] bg-[var(--color-bg)]/40">
106	          <div className="border-b border-[var(--color-border)] px-3 py-3">
107	            <Field label="Day">
108	              <select
109	                value={day ?? ""}
110	                onChange={(e) => setDay(Number(e.target.value))}
111	                disabled={!days || days.length === 0}
112	                className="h-7 w-full appearance-none rounded-md border border-[var(--color-border-2)] bg-[var(--color-surface)] px-2 font-mono text-[17.5px] text-[var(--color-fg)]"
113	              >
114	                {(days ?? []).map((d) => (
115	                  <option key={d.day} value={d.day}>
116	                    day-{String(d.day).padStart(2, "0")}
117	                    {d.content_date ? `  ·  ${d.content_date}` : ""}
118	                  </option>
119	                ))}
120	              </select>
121	            </Field>
122	            <div className="mt-2 flex gap-1">
123	              {(Object.keys(KIND_LABELS) as Kind[]).map((k) => (
124	                <button
125	                  key={k}
126	                  onClick={() => setKind(k)}
127	                  className={cn(
128	                    "flex-1 rounded-md border px-2 py-1 font-mono text-[16.5px] uppercase tracking-wide transition-colors",
129	                    kind === k
130	                      ? "border-[var(--color-accent-dim)] bg-[var(--color-surface)] text-[var(--color-accent)]"
131	                      : "border-[var(--color-border-2)] bg-[var(--color-bg)] text-[var(--color-fg-muted)] hover:text-[var(--color-fg)]",
132	                  )}
133	                >
134	                  {KIND_LABELS[k]} ({currentDay ? currentDay[k === "bank" ? "bank" : k === "invoice" ? "invoices" : "emails"].length : 0})
135	                </button>
136	              ))}
137	            </div>
138	          </div>
139	
140	          <div className="min-h-0 flex-1 overflow-auto px-1.5 py-2">
141	            {items.length === 0 ? (
142	              <p className="px-3 py-6 text-center text-[17.5px] text-[var(--color-fg-muted)]">
143	                No items.
144	              </p>
145	            ) : (
146	              items.map((it) => (
147	                <button
148	                  key={it.id}
149	                  onClick={() => setItemId(it.id)}
150	                  className={cn(
151	                    "mb-1 block w-full rounded-md border px-2.5 py-2 text-left transition-colors",
152	                    itemId === it.id
153	                      ? "border-[var(--color-accent-dim)] bg-[var(--color-surface)]"
154	                      : "border-transparent hover:border-[var(--color-border-2)] hover:bg-[var(--color-surface)]/60",
155	                  )}
156	                >
157	                  <div className="flex items-center gap-2">
158	                    <span className="font-mono text-[16px] text-[var(--color-accent)]">
159	                      {it.id}
160	                    </span>
161	                  </div>
162	                  <div className="mt-0.5 line-clamp-1 text-[18px] font-medium text-[var(--color-fg)]">
163	                    {it.label}
164	                  </div>
165	                  <div className="mt-0.5 line-clamp-2 text-[16.5px] text-[var(--color-fg-muted)]">
166	                    {it.detail}
167	                  </div>
168	                </button>
169	              ))
170	            )}
171	          </div>
172	
173	          <div className="border-t border-[var(--color-border)] px-3 py-3">
174	            <Field label="Mode">
175	              <div className="flex gap-1">
176	                {(["isolated", "live"] as Mode[]).map((m) => (
177	                  <button
178	                    key={m}
179	                    onClick={() => setMode(m)}
180	                    className={cn(
181	                      "flex-1 rounded-md border px-2 py-1 font-mono text-[16.5px] transition-colors",
182	                      mode === m
183	                        ? "border-[var(--color-accent-dim)] bg-[var(--color-surface)] text-[var(--color-accent)]"
184	                        : "border-[var(--color-border-2)] bg-[var(--color-bg)] text-[var(--color-fg-muted)] hover:text-[var(--color-fg)]",
185	                    )}
186	                  >
187	                    {m}
188	                  </button>
189	                ))}
190	              </div>
191	              <p className="mt-1 text-[16px] text-[var(--color-fg-muted)]">
192	                {mode === "isolated"
193	                  ? "Fresh tmp wiki per run. Real Gemini, no live mutation."
194	                  : "Writes to wiki/LIE-001 + commits."}
195	              </p>
196	            </Field>
197	            <button
198	              onClick={handleRun}
199	              disabled={!itemId || running}
200	              className={cn(
201	                "mt-3 w-full rounded-md border px-3 py-2 font-mono text-[17.5px] font-medium transition-colors",
202	                running
203	                  ? "border-[var(--color-border-2)] bg-[var(--color-surface)] text-[var(--color-fg-muted)]"
204	                  : "border-[var(--color-accent)] bg-[var(--color-accent)] text-[#0b0b0a] hover:opacity-90",
205	                !itemId && "cursor-not-allowed opacity-50",
206	              )}
207	            >
208	              {running ? "Running…" : `▶ Run ingest (${itemId ?? "—"})`}
209	            </button>
210	          </div>
211	        </aside>
212	
213	        <main className="flex min-w-0 flex-1 flex-col">
214	          {error && (
215	            <div className="border-b border-red-500/40 bg-red-500/10 px-4 py-2 text-[17.5px] text-red-400">
216	              {error}
217	            </div>
218	          )}
219	          {!result && !running && !error && (
220	            <div className="grid flex-1 place-items-center text-[18px] text-[var(--color-fg-muted)]">
221	              Pick a day + item, then run. Uses real Gemini ({"gemini-2.5-flash-lite"} → {"gemini-2.5-pro"}).
222	            </div>
223	          )}
224	          {running && (
225	            <div className="grid flex-1 place-items-center text-[18px] text-[var(--color-fg-muted)]">
226	              Calling supervisor → classify → resolve → extract → patch → commit…
227	            </div>
228	          )}
229	          {result && (
230	            <ResultView
231	              result={result}
232	              activeFile={activeFile}
233	              onActiveFile={setActiveFile}
234	              activeContent={activeContent}
235	            />
236	          )}
237	        </main>
238	      </div>
239	    </div>
240	  );
241	}
242	
243	function Field({
244	  label,
245	  children,
246	}: {
247	  label: string;
248	  children: React.ReactNode;
249	}) {
250	  return (
251	    <label className="block">
252	      <span className="block pb-1 font-mono text-[16px] uppercase tracking-[0.2em] text-[var(--color-fg-dim)]">
253	        {label}
254	      </span>
255	      {children}
256	    </label>
257	  );
258	}
259	
260	function ResultView({
261	  result,
262	  activeFile,
263	  onActiveFile,
264	  activeContent,
265	}: {
266	  result: SimIngestResponse;
267	  activeFile: string | null;
268	  onActiveFile: (p: string) => void;
269	  activeContent: string;
270	}) {
271	  return (
272	    <div className="flex min-h-0 flex-1 flex-col">
273	      <div className="grid grid-cols-2 gap-x-6 gap-y-1 border-b border-[var(--color-border)] px-4 py-3 font-mono text-[17px]">
274	        <Stat label="status" value={result.status} accent />
275	        <Stat label="duration" value={`${result.duration_ms} ms`} />
276	        <Stat label="applied_ops" value={String(result.applied_ops)} />
277	        <Stat
278	          label="provider"
279	          value={`${result.provider} (${result.fast_model} → ${result.smart_model})`}
280	        />
281	        <Stat
282	          label="commit"
283	          value={result.commit_sha ? result.commit_sha.slice(0, 10) : "—"}
284	        />
285	        <Stat label="idempotent" value={String(result.idempotent)} />
286	        {result.classification && (
287	          <>
288	            <Stat
289	              label="classify.signal"
290	              value={String(result.classification.signal)}
291	              accent={result.classification.signal}
292	            />
293	            <Stat
294	              label="classify"
295	              value={`${result.classification.category}  ·  ${result.classification.priority}  ·  conf=${result.classification.confidence}`}
296	            />
297	          </>
298	        )}
299	        <Stat label="workspace" value={result.workspace} colSpan={2} mono />
300	      </div>
301	
302	      <div className="flex min-h-0 flex-1">
303	        <aside className="flex w-[260px] shrink-0 flex-col border-r border-[var(--color-border)]">
304	          <div className="border-b border-[var(--color-border)] px-3 py-2 font-mono text-[16px] uppercase tracking-[0.2em] text-[var(--color-fg-dim)]">
305	            Touched files ({result.files.length})
306	          </div>
307	          <div className="min-h-0 flex-1 overflow-auto px-1.5 py-1.5">
308	            {result.files.map((f) => (
309	              <button
310	                key={f.path}
311	                onClick={() => onActiveFile(f.path)}
312	                className={cn(
313	                  "block w-full truncate rounded px-2 py-1 text-left font-mono text-[17px]",
314	                  activeFile === f.path
315	                    ? "bg-[var(--color-surface)] text-[var(--color-accent)]"
316	                    : "text-[var(--color-fg-muted)] hover:bg-[var(--color-surface)]/60 hover:text-[var(--color-fg)]",
317	                )}
318	              >
319	                {f.path}
320	              </button>
321	            ))}
322	          </div>
323	          {result.git_log.length > 0 && (
324	            <div className="border-t border-[var(--color-border)] px-3 py-2">
325	              <div className="pb-1 font-mono text-[16px] uppercase tracking-[0.2em] text-[var(--color-fg-dim)]">
326	                git log
327	              </div>
328	              <ul className="space-y-0.5 font-mono text-[16px] text-[var(--color-fg-muted)]">
329	                {result.git_log.map((ln) => (
330	                  <li key={ln} className="truncate">
331	                    {ln}
332	                  </li>
333	                ))}
334	              </ul>
335	            </div>
336	          )}
337	        </aside>
338	
339	        <section className="prose min-w-0 flex-1 overflow-auto px-6 py-4 text-[19px] dark:prose-invert">
340	          {activeFile ? (
341	            <>
342	              <div className="mb-3 font-mono text-[16px] uppercase tracking-[0.2em] text-[var(--color-fg-dim)]">
343	                {activeFile}
344	              </div>
345	              <ReactMarkdown remarkPlugins={[remarkGfm]}>
346	                {activeContent}
347	              </ReactMarkdown>
348	            </>
349	          ) : (
350	            <p className="text-[var(--color-fg-muted)]">No files touched.</p>
351	          )}
352	        </section>
353	      </div>
354	    </div>
355	  );
356	}
357	
358	function Stat({
359	  label,
360	  value,
361	  accent,
362	  mono,
363	  colSpan,
364	}: {
365	  label: string;
366	  value: string;
367	  accent?: boolean;
368	  mono?: boolean;
369	  colSpan?: number;
370	}) {
371	  return (
372	    <div className={colSpan === 2 ? "col-span-2" : ""}>
373	      <span className="text-[var(--color-fg-dim)]">{label}</span>{" "}
374	      <span
375	        className={cn(
376	          accent && "text-[var(--color-accent)]",
377	          mono && "break-all",
378	        )}
379	      >
380	        {value}
381	      </span>
382	    </div>
383	  );
384	}
