function handleStage(ev: SimStageEvent) {
  const raw = ev.stage;
  const isDone = raw.endsWith(".done");
  const key = isDone ? raw.slice(0, -5) : raw;
  if (raw === "done") {
    const status = (ev.data?.status as "applied" | "no_signal") ?? null;
    setTerminalStatus(status);
    setActiveStage(null);
    if (status === "no_signal") {
      setStages((prev) => {
        const next = { ...prev };
        for (const n of PIPELINE) {
          if (
            n.key !== "normalize" &&
            n.key !== "classify" &&
            next[n.key].state === "pending"
          ) {
            next[n.key] = { ...next[n.key], state: "skipped" };
          }
        }
        return next;
      });
    }
    return;
  }
  if (!PIPELINE.some((n) => n.key === key)) return;
  setStages((prev) => {
    const cur = prev[key];
    const now = performance.now();
    if (isDone) {
      return {
        ...prev,
        [key]: {
          ...cur,
          state: "done",
          data: ev.data,
          endedAt: now,
        },
      };
    }
    return {
      ...prev,
      [key]: {
        ...cur,
        state: "active",
        startedAt: now,
      },
    };
  });
  if (!isDone) setActiveStage(key);
}

async function handleRun() {
  if (!day || !itemId) return;
  setRunning(true);
  setError(null);
  setResult(null);
  setStages(emptyStages());
  setActiveStage(null);
  setTerminalStatus(null);
  try {
    await runSimIngestStream(
      { day, kind, id: itemId, mode },
      {
        onStage: handleStage,
        onResponse: (resp) => setResult(resp),
        onError: (err) => setError(`${err.status}: ${err.detail}`),
      },
    );
  } catch (e) {
    setError(String(e));
  } finally {
    setRunning(false);
    setActiveStage(null);
  }
}

