function chipSummary(
  label: string,
  data: Record<string, unknown> | null,
): string | null {
  if (!data) return null;
  if (label === "classify") {
    const cat = data.category as string | undefined;
    const conf = data.confidence as number | undefined;
    if (cat) return `${cat} ${conf != null ? `· ${conf}` : ""}`.trim();
