  if (label === "normalize") {
    const chars = data.chars as number | undefined;
    if (typeof chars === "number") return `${chars} chars`;
  }
  if (label === "reindex") {
    const c = data.count as number | undefined;
    if (typeof c === "number") return `${c} files`;
