function handleStage(ev: SimStageEvent) {
  const raw = ev.stage;
  const isDone = raw.endsWith(".done");
  const key = isDone ? raw.slice(0, -5) : raw;
  if (raw === "done") {
    const status = (ev.data?.status as "applied" | "no_signal") ?? null;
    setTerminalStatus(status);
    setActiveStage(null);
    if (status === "no_signal") {
      setStages((prev) => {
        const next = { ...prev };
        for (const n of PIPELINE) {
          if (
            n.key !== "normalize" &&
            n.key !== "classify" &&
            next[n.key].state === "pending"
