            next[n.key] = { ...next[n.key], state: "skipped" };
          }
        }
        return next;
      });
    }
    return;
  }
  if (!PIPELINE.some((n) => n.key === key)) return;
  setStages((prev) => {
    const cur = prev[key];
    const now = performance.now();
    if (isDone) {
      return {
        ...prev,
        [key]: {
          ...cur,
          state: "done",
          data: ev.data,
          endedAt: now,
        },
      };
    }
    return {
      ...prev,
      [key]: {
        ...cur,
        state: "active",
        startedAt: now,
      },
    };
  });
  if (!isDone) setActiveStage(key);
}

